    else:
        return data

def power_transformation(data, power=2):
    # Apply power transformation if the validation set has outliers
    if np.any(np.isinf(data)) or np.any(np.isnan(data)):
        return data ** power
    else:
        return data

def winsorization(data, lower_percentile=5, upper_percentile=95):
    # Winsorize data if the validation set has outliers
    lower_bound = np.percentile(data, lower_percentile)
    upper_bound = np.percentile(data, upper_percentile)
    data_winsorized = np.clip(data, lower_bound, upper_bound)
    return data_winsorized
